import can
import pytest
import time

MSG_ID_GW_VEHICLE_STATUS = 0xC8

@pytest.fixture(scope="module")
def can_bus():
    bus = can.Bus(bustype="socketcan", channel="can0", bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, arb_id, duration_sec):
    messages = []
    end_time = time.time() + duration_sec
    while time.time() < end_time:
        msg = bus.recv(timeout=0.5)
        if msg and msg.arbitration_id == arb_id:
            messages.append(msg)
    return messages

def decode_any_door_open(msg):
    return (msg.data[2] >> 0) & 0x01

test_cases.python_test_script:
def test_tc_gw_door_001_all_closed(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 0

def test_tc_gw_door_002_driver_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_003_passenger_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_door_004_both_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_GW_VEHICLE_STATUS, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1
